eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   bhagavadGita: () => (/* binding */ bhagavadGita),\n/* harmony export */   books: () => (/* binding */ books),\n/* harmony export */   getBookBySlug: () => (/* binding */ getBookBySlug),\n/* harmony export */   getChapterByNumber: () => (/* binding */ getChapterByNumber),\n/* harmony export */   getConceptsForVerse: () => (/* binding */ getConceptsForVerse),\n/* harmony export */   getSourcesForVerse: () => (/* binding */ getSourcesForVerse),\n/* harmony export */   getVerseByNumber: () => (/* binding */ getVerseByNumber)\n/* harmony export */ });\nconst concepts = [\n    {\n        slug: \"dharma\",\n        name: \"Dharma\",\n        category: \"Ethics\",\n        description: \"Right action, responsibility, and alignment with truth in a specific context.\"\n    },\n    {\n        slug: \"atma\",\n        name: \"Atma\",\n        category: \"Self-knowledge\",\n        description: \"The witnessing self discussed in the Gita as deeper than bodily change.\"\n    },\n    {\n        slug: \"karma-yoga\",\n        name: \"Karma Yoga\",\n        category: \"Practice\",\n        description: \"A discipline of sincere action without dependence on personal reward.\"\n    },\n    {\n        slug: \"samatva\",\n        name: \"Samatva\",\n        category: \"Mind training\",\n        description: \"Equanimity: steadiness across success, failure, pleasure, and pain.\"\n    },\n    {\n        slug: \"titiksha\",\n        name: \"Titiksha\",\n        category: \"Practice\",\n        description: \"Forbearance toward changing sensations and circumstances.\"\n    },\n    {\n        slug: \"arjuna-vishada\",\n        name: \"Arjuna Vishada\",\n        category: \"Human condition\",\n        description: \"Arjuna's crisis as the doorway into inquiry, humility, and learning.\"\n    }\n];\nconst sources = [\n    {\n        slug: \"bhagavad-gita-scripture\",\n        title: \"Bhagavad Gita\",\n        sourceType: \"SCRIPTURE\",\n        citation: \"Bhagavad Gita, traditional Sanskrit recension.\"\n    },\n    {\n        slug: \"shlokam-gita-reference\",\n        title: \"Shlokam.org Bhagavad Gita Verse Reference\",\n        sourceType: \"REFERENCE\",\n        citation: \"Public verse reference for Sanskrit, transliteration, and word meanings.\",\n        url: \"https://shlokam.org/gita/\"\n    },\n    {\n        slug: \"bhagavadgita-com-reference\",\n        title: \"BhagavadGita.com Verse Reference\",\n        sourceType: \"REFERENCE\",\n        citation: \"Public verse reference consulted for Sanskrit and transliteration comparison.\",\n        url: \"https://www.bhagavadgita.com/\"\n    }\n];\nconst chapters = [\n    {\n        number: 1,\n        slug: \"arjuna-vishada-yoga\",\n        title: \"Arjuna Vishada Yoga\",\n        summary: \"The battlefield becomes a mirror for moral confusion, grief, and the need for deeper wisdom.\",\n        overview: \"Chapter 1 does not begin with abstract philosophy. It begins with a human being overwhelmed by conflict. Arjuna sees teachers, relatives, and friends on both sides and becomes unable to act with clarity. This prepares the ground for the Gita's teaching: wisdom begins when we stop pretending confusion is certainty.\",\n        verses: [\n            {\n                number: 1,\n                slug: \"dharmakshetre-kurukshetre\",\n                sanskrit: \"धृतराष्ट्र उवाच ।\\nधर्मक्षेत्रे कुरुक्षेत्रे समवेता युयुत्सवः ।\\nमामकाः पाण्डवाश्चैव किमकुर्वत सञ्जय ॥ १-१॥\",\n                transliteration: \"dhṛtarāṣṭra uvāca\\ndharmakṣetre kurukṣetre samavetā yuyutsavaḥ\\nmāmakāḥ pāṇḍavāścaiva kimakurvata sañjaya\",\n                wordByWord: \"dhṛtarāṣṭra uvāca: Dhritarashtra said; dharmakṣetre: in the field of dharma; kurukṣetre: in Kurukshetra; samavetāḥ: assembled; yuyutsavaḥ: wishing to fight; māmakāḥ: my people; pāṇḍavāḥ: the sons of Pandu; ca eva: and also; kim akurvata: what did they do; sañjaya: O Sanjaya.\",\n                practicalApplication: \"Before judging a situation, notice the lens through which you are asking the question. Dhritarashtra's 'my people' already reveals attachment.\",\n                philosophyInsight: \"The verse frames the battlefield as both historical setting and moral field. This is an interpretive reading, not a claim that the verse only has one meaning.\",\n                conceptSlugs: [\n                    \"dharma\",\n                    \"arjuna-vishada\"\n                ],\n                sourceSlugs: [\n                    \"bhagavad-gita-scripture\",\n                    \"shlokam-gita-reference\"\n                ],\n                meaningLayers: [\n                    {\n                        type: \"SIMPLE\",\n                        title: \"What is happening?\",\n                        body: \"Dhritarashtra asks Sanjaya what happened when the two sides gathered at Kurukshetra, ready for battle.\"\n                    },\n                    {\n                        type: \"BEGINNER\",\n                        title: \"Why this opening matters\",\n                        body: \"The Gita opens with a question shaped by attachment. Dhritarashtra separates 'mine' from 'the Pandavas', showing how partiality can cloud perception.\"\n                    },\n                    {\n                        type: \"PHILOSOPHICAL\",\n                        title: \"The field as a moral space\",\n                        body: \"Kurukshetra is called dharmakṣetra, a field of dharma. A reader may interpret this as a reminder that external conflict often reveals an inner ethical field.\"\n                    }\n                ],\n                commentaries: [\n                    {\n                        author: \"Bhagwatsharanpriy Study Note\",\n                        tradition: \"Learning guide\",\n                        title: \"Attachment appears before the teaching begins\",\n                        body: \"The verse is not yet giving instruction; it is exposing the condition that makes instruction necessary. The questioner is anxious, invested, and divided.\",\n                        interpretationNote: \"This is a pedagogical interpretation for learners, not scripture text.\"\n                    }\n                ]\n            },\n            {\n                number: 21,\n                slug: \"senayor-ubhayor-madhye\",\n                sanskrit: \"अर्जुन उवाच ।\\nसेनयोरुभयोर्मध्ये रथं स्थापय मेऽच्युत ॥ १-२१॥\",\n                transliteration: \"arjuna uvāca\\nsenayorubhayormadhye rathaṃ sthāpaya me'cyuta\",\n                wordByWord: \"arjuna uvāca: Arjuna said; senayoḥ: of the armies; ubhayoḥ: of both; madhye: in the middle; ratham: chariot; sthāpaya: place; me: my; acyuta: O Achyuta.\",\n                practicalApplication: \"When a difficult choice feels abstract, look directly at the real people, duties, and consequences involved.\",\n                philosophyInsight: \"Arjuna asks to see clearly before acting. In the Gita's narrative arc, clear seeing first intensifies pain, then opens the need for wisdom.\",\n                conceptSlugs: [\n                    \"dharma\",\n                    \"arjuna-vishada\"\n                ],\n                sourceSlugs: [\n                    \"bhagavad-gita-scripture\",\n                    \"shlokam-gita-reference\"\n                ],\n                meaningLayers: [\n                    {\n                        type: \"SIMPLE\",\n                        title: \"Arjuna asks to see\",\n                        body: \"Arjuna asks Krishna to place the chariot between the two armies.\"\n                    },\n                    {\n                        type: \"PRACTICAL\",\n                        title: \"Do not avoid the full picture\",\n                        body: \"The verse can be practiced as a principle of honest attention: move closer to reality before making a serious decision.\"\n                    },\n                    {\n                        type: \"DEEP\",\n                        title: \"The chariot becomes a classroom\",\n                        body: \"The center of the battlefield becomes the center of inquiry. The place of conflict becomes the place where teaching can begin.\"\n                    }\n                ],\n                commentaries: [\n                    {\n                        author: \"Bhagwatsharanpriy Study Note\",\n                        tradition: \"Learning guide\",\n                        title: \"Courage before clarity\",\n                        body: \"Arjuna's request appears strategic, but it becomes existential. Seeing the field clearly reveals that the problem is not only military; it is moral and spiritual.\",\n                        interpretationNote: \"This note distinguishes narrative development from literal translation.\"\n                    }\n                ]\n            }\n        ]\n    },\n    {\n        number: 2,\n        slug: \"sankhya-yoga\",\n        title: \"Sankhya Yoga\",\n        summary: \"Krishna begins teaching the nature of the self, disciplined action, equanimity, and wise understanding.\",\n        overview: \"Chapter 2 is the Gita in seed form. It addresses grief, the changing body, sense experience, steady action, and the inner poise called yoga. For beginners, it is best read slowly: each verse adds a layer to the question of how to live wisely.\",\n        verses: [\n            {\n                number: 13,\n                slug: \"dehinosmin-yatha-dehe\",\n                sanskrit: \"देहिनोऽस्मिन्यथा देहे कौमारं यौवनं जरा ।\\nतथा देहान्तरप्राप्तिर्धीरस्तत्र न मुह्यति ॥ २-१३॥\",\n                transliteration: \"dehino'sminyathā dehe kaumāraṃ yauvanaṃ jarā\\ntathā dehāntaraprāptir dhīrastatra na muhyati\",\n                wordByWord: \"dehinaḥ: of the embodied; asmin: in this; yathā: just as; dehe: in the body; kaumāram: childhood; yauvanam: youth; jarā: old age; tathā: so also; dehāntara-prāptiḥ: attainment of another body; dhīraḥ: the steady one; tatra: there; na muhyati: is not deluded.\",\n                practicalApplication: \"Observe change without immediately confusing change with loss of identity. This can soften fear and make reflection possible.\",\n                philosophyInsight: \"The verse teaches continuity through bodily change. Traditions interpret this continuity through the doctrine of the self; the app labels that as philosophical interpretation.\",\n                conceptSlugs: [\n                    \"atma\",\n                    \"samatva\"\n                ],\n                sourceSlugs: [\n                    \"bhagavad-gita-scripture\",\n                    \"shlokam-gita-reference\",\n                    \"bhagavadgita-com-reference\"\n                ],\n                meaningLayers: [\n                    {\n                        type: \"SIMPLE\",\n                        title: \"The basic point\",\n                        body: \"The embodied person passes through childhood, youth, and old age. The wise do not become confused by this change.\"\n                    },\n                    {\n                        type: \"BEGINNER\",\n                        title: \"A gentle way to understand it\",\n                        body: \"You have already lived through many versions of your body and life. The verse asks you to notice the continuity that remains present through change.\"\n                    },\n                    {\n                        type: \"PHILOSOPHICAL\",\n                        title: \"Self and body\",\n                        body: \"Within the Gita's worldview, the self is not reduced to the body. This is a metaphysical teaching, not a scientific measurement.\"\n                    },\n                    {\n                        type: \"SCIENTIFIC_PARALLEL\",\n                        title: \"A careful parallel\",\n                        body: \"Modern psychology also notices continuity of identity across changing life stages. This is only a parallel for reflection, not proof of the Gita's metaphysics.\"\n                    }\n                ],\n                commentaries: [\n                    {\n                        author: \"Bhagwatsharanpriy Study Note\",\n                        tradition: \"Learning guide\",\n                        title: \"Change is not the whole truth\",\n                        body: \"This verse invites the learner to hold two facts together: the body changes, and experience still has a thread of continuity. The Gita uses that insight to begin a deeper inquiry into the self.\",\n                        interpretationNote: \"This is interpretive explanation, not a literal translation.\"\n                    },\n                    {\n                        author: \"Traditional Orientation\",\n                        tradition: \"Vedanta\",\n                        title: \"A doorway into atma-vichara\",\n                        body: \"Vedantic readers often treat this verse as an early doorway into inquiry about the witnessing self. The verse is studied carefully because it shifts attention from events to the knower of events.\",\n                        interpretationNote: \"This summarizes a broad traditional reading without claiming one exclusive school view.\"\n                    }\n                ]\n            },\n            {\n                number: 14,\n                slug: \"matrasparsas-tu-kaunteya\",\n                sanskrit: \"मात्रास्पर्शास्तु कौन्तेय शीतोष्णसुखदुःखदाः ।\\nआगमापायिनोऽनित्या स्तांस्तितिक्षस्व भारत ॥ २-१४॥\",\n                transliteration: \"mātrāsparśāstu kaunteya śītoṣṇasukhaduḥkhadāḥ\\nāgamāpāyino'nityā stāṃstitikṣasva bhārata\",\n                wordByWord: \"mātrāsparśāḥ: contacts of senses; tu: indeed; kaunteya: O son of Kunti; śītoṣṇa-sukha-duḥkha-dāḥ: giving cold, heat, pleasure, and pain; āgamāpāyinaḥ: coming and going; anityāḥ: impermanent; tān: them; titikṣasva: endure; bhārata: O descendant of Bharata.\",\n                practicalApplication: \"When discomfort arises, name it as a passing experience before reacting. This creates a small space for wise action.\",\n                philosophyInsight: \"The verse does not deny pleasure or pain. It places them in the category of changing experience and asks for steadiness toward them.\",\n                conceptSlugs: [\n                    \"titiksha\",\n                    \"samatva\"\n                ],\n                sourceSlugs: [\n                    \"bhagavad-gita-scripture\",\n                    \"shlokam-gita-reference\",\n                    \"bhagavadgita-com-reference\"\n                ],\n                meaningLayers: [\n                    {\n                        type: \"SIMPLE\",\n                        title: \"Experiences come and go\",\n                        body: \"Heat, cold, pleasure, and pain arise through contact with the senses. They are temporary, so Krishna asks Arjuna to endure them.\"\n                    },\n                    {\n                        type: \"PRACTICAL\",\n                        title: \"Training the pause\",\n                        body: \"Titiksha is not numbness. It is the ability to stay present long enough that discomfort does not command your whole mind.\"\n                    },\n                    {\n                        type: \"SCIENTIFIC_PARALLEL\",\n                        title: \"A careful parallel\",\n                        body: \"Emotion regulation research also values the pause between stimulus and response. This is a practical parallel, not a claim that the verse is a psychology textbook.\"\n                    }\n                ],\n                commentaries: [\n                    {\n                        author: \"Bhagwatsharanpriy Study Note\",\n                        tradition: \"Learning guide\",\n                        title: \"Endurance without hardness\",\n                        body: \"The verse can be misunderstood as suppressing feeling. A gentler reading is that changing experiences should be felt clearly without becoming the ruler of action.\",\n                        interpretationNote: \"This is a practical interpretation for study.\"\n                    }\n                ]\n            },\n            {\n                number: 47,\n                slug: \"karmanyevadhikaraste\",\n                sanskrit: \"कर्मण्येवाधिकारस्ते मा फलेषु कदाचन ।\\nमा कर्मफलहेतुर्भूर्मा ते सङ्गोऽस्त्वकर्मणि ॥ २-४७॥\",\n                transliteration: \"karmaṇyevādhikāraste mā phaleṣu kadācana\\nmā karmaphalaheturbhūrmā te saṅgo'stvakarmaṇi\",\n                wordByWord: \"karmaṇi: in action; eva: only; adhikāraḥ: right or sphere of responsibility; te: your; mā: not; phaleṣu: in the fruits; kadācana: ever; mā: do not; karmaphalahetuḥ: cause of the fruits of action; bhūḥ: be; mā: do not; te: your; saṅgaḥ: attachment; astu: let there be; akarmaṇi: in inaction.\",\n                practicalApplication: \"Give full attention to the action you can honestly perform. Release the demand that reality must obey your preferred result.\",\n                philosophyInsight: \"This verse is a core seed of Karma Yoga. It separates responsibility for action from possession of outcome.\",\n                conceptSlugs: [\n                    \"karma-yoga\",\n                    \"dharma\",\n                    \"samatva\"\n                ],\n                sourceSlugs: [\n                    \"bhagavad-gita-scripture\",\n                    \"shlokam-gita-reference\",\n                    \"bhagavadgita-com-reference\"\n                ],\n                meaningLayers: [\n                    {\n                        type: \"SIMPLE\",\n                        title: \"Your work is yours\",\n                        body: \"You have responsibility for action, but not ownership over every result that follows from it.\"\n                    },\n                    {\n                        type: \"BEGINNER\",\n                        title: \"Not a call to indifference\",\n                        body: \"The verse does not say results do not matter. It says attachment to results should not become the motive that controls the mind.\"\n                    },\n                    {\n                        type: \"PRACTICAL\",\n                        title: \"A practice sentence\",\n                        body: \"Before beginning work, say: I will act with care; I will learn from the result; I do not need the result to define me.\"\n                    },\n                    {\n                        type: \"DEEP\",\n                        title: \"Action without inner bargaining\",\n                        body: \"Karma Yoga trains action that is sincere, skillful, and less entangled in egoic bargaining with the future.\"\n                    }\n                ],\n                commentaries: [\n                    {\n                        author: \"Bhagwatsharanpriy Study Note\",\n                        tradition: \"Learning guide\",\n                        title: \"Freedom inside effort\",\n                        body: \"The verse protects effort from two distortions: obsession with reward and escape into inaction. Both keep the mind bound to the result.\",\n                        interpretationNote: \"This is an explanatory interpretation, not scripture text.\"\n                    },\n                    {\n                        author: \"Traditional Orientation\",\n                        tradition: \"Karma Yoga\",\n                        title: \"The discipline of offering action\",\n                        body: \"Traditional Karma Yoga readings often understand this as action offered beyond personal reward. The emphasis is not laziness but purified motivation.\",\n                        interpretationNote: \"This is a broad traditional orientation and should not be treated as a single authoritative commentary.\"\n                    }\n                ]\n            },\n            {\n                number: 48,\n                slug: \"yogasthah-kuru-karmani\",\n                sanskrit: \"योगस्थः कुरु कर्माणि सङ्गं त्यक्त्वा धनञ्जय ।\\nसिद्ध्यसिद्ध्योः समो भूत्वा समत्वं योग उच्यते ॥ २-४८॥\",\n                transliteration: \"yogasthaḥ kuru karmāṇi saṅgaṃ tyaktvā dhanañjaya\\nsiddhyasiddhyoḥ samo bhūtvā samatvaṃ yoga ucyate\",\n                wordByWord: \"yogasthaḥ: established in yoga; kuru: perform; karmāṇi: actions; saṅgam: attachment; tyaktvā: abandoning; dhanañjaya: O Dhananjaya; siddhy-asiddhyoḥ: in success and failure; samaḥ: balanced; bhūtvā: becoming; samatvam: equanimity; yogaḥ: yoga; ucyate: is called.\",\n                practicalApplication: \"After doing your best, practice meeting both success and failure as information, not as the final measure of your worth.\",\n                philosophyInsight: \"The verse defines yoga here as samatva, evenness of mind. This is one important definition within the Gita's wider teaching.\",\n                conceptSlugs: [\n                    \"karma-yoga\",\n                    \"samatva\"\n                ],\n                sourceSlugs: [\n                    \"bhagavad-gita-scripture\",\n                    \"shlokam-gita-reference\",\n                    \"bhagavadgita-com-reference\"\n                ],\n                meaningLayers: [\n                    {\n                        type: \"SIMPLE\",\n                        title: \"Yoga as steadiness\",\n                        body: \"Krishna asks Arjuna to act while remaining balanced in success and failure. This evenness is called yoga.\"\n                    },\n                    {\n                        type: \"PHILOSOPHICAL\",\n                        title: \"A definition of yoga\",\n                        body: \"Here, yoga is not primarily posture or technique. It is a stable inner relationship to action and outcome.\"\n                    },\n                    {\n                        type: \"PRACTICAL\",\n                        title: \"Success and failure practice\",\n                        body: \"When a result arrives, ask first: What does this teach? This keeps the mind in learning before pride or despair takes over.\"\n                    }\n                ],\n                commentaries: [\n                    {\n                        author: \"Bhagwatsharanpriy Study Note\",\n                        tradition: \"Learning guide\",\n                        title: \"Equanimity is not passivity\",\n                        body: \"Equanimity does not make action weak. It makes action cleaner because the mind is less thrown around by praise, blame, winning, and losing.\",\n                        interpretationNote: \"This is a practical interpretation for learners.\"\n                    }\n                ]\n            }\n        ]\n    }\n];\nconst bhagavadGita = {\n    slug: \"bhagavad-gita\",\n    title: \"Bhagavad Gita\",\n    subtitle: \"A guided study of wisdom, action, self-knowledge, and devotion\",\n    tradition: \"Sanatana Dharma\",\n    difficulty: \"BEGINNER\",\n    summary: \"A sacred dialogue between Krishna and Arjuna on the battlefield of Kurukshetra, exploring duty, self-knowledge, disciplined action, devotion, and liberation.\",\n    beginnerSummary: \"Begin with the Gita as a conversation about confusion and clarity. Arjuna is overwhelmed, and Krishna teaches him how to see himself, his duty, and reality more deeply.\",\n    tags: [\n        \"Dharma\",\n        \"Karma Yoga\",\n        \"Self-knowledge\",\n        \"Equanimity\",\n        \"Devotion\"\n    ],\n    concepts,\n    sources,\n    chapters\n};\nconst books = [\n    bhagavadGita\n];\nfunction getBookBySlug(slug) {\n    return books.find((book)=>book.slug === slug);\n}\nfunction getChapterByNumber(bookSlug, chapterNumber) {\n    const book = getBookBySlug(bookSlug);\n    return book?.chapters.find((chapter)=>chapter.number === chapterNumber);\n}\nfunction getVerseByNumber(bookSlug, chapterNumber, verseNumber) {\n    const chapter = getChapterByNumber(bookSlug, chapterNumber);\n    return chapter?.verses.find((verse)=>verse.number === verseNumber);\n}\nfunction getConceptsForVerse(book, verse) {\n    return verse.conceptSlugs.map((slug)=>book.concepts.find((concept)=>concept.slug === slug)).filter((concept)=>Boolean(concept));\n}\nfunction getSourcesForVerse(book, verse) {\n    return verse.sourceSlugs.map((slug)=>book.sources.find((source)=>source.slug === slug)).filter((source)=>Boolean(source));\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/content/gita.ts\n");

